final:
module top_module(
    input [3:0] data_in,
    input [1:0] shift_amount,
    input direction_left,
    output reg [3:0] data_out
);reg [3:0] data_cache [1:3];

always @(*) begin
    data_cache[1] = data_in;
    data_cache[2] = data_cache[1] << 1;
    data_cache[3] = data_cache[2] << 1;

    if (shift_amount == 2'b00) begin
        data_out = data_in;
    end else if (shift_amount == 2'b01) begin
        data_out = data_cache[2];
    end else if (shift_amount == 2'b10) begin
        data_out = data_cache[3];
    end else if (shift_amount == 2'b11) begin
        data_out = direction_left ? data_cache[3] : data_cache[1];
    end
end

endmodule
